import { Lesson } from './types';
import { createLesson } from './data_helpers';

export const matLessonsB1: Lesson[] = [
  createLesson('g3-mat-b1-l1', 'L1: 3ª Série — Diagnóstico e Revisão Geral', 'matematica', 'A 3ª Série é o ano de consolidação e preparação para o ENEM e vestibulares. Diagnóstico completo: avaliar domínio dos conteúdos da 1ª e 2ª Série — funções (1º grau, 2º grau, exponencial, logarítmica), geometria plana e espacial, trigonometria, probabilidade, estatística. Identificação de lacunas prioritárias. O ENEM de Matemática cobre toda a Educação Básica, mas 60% das questões estão nos últimos 2 anos do Ensino Médio. Estratégia de estudo: revisão sistemática + prática intensiva de questões contextualizadas. A matemática do ENEM não é só cálculo — exige interpretação de gráficos, tabelas, situações do cotidiano, geometria espacial e raciocínio lógico. Simulado diagnóstico de 10 questões.', ['Após o diagnóstico, em qual área da matemática você tem mais dificuldade? Qual é seu plano para superar essa dificuldade?', 'Resolva o simulado diagnóstico. Para cada erro, identifique o conteúdo que precisa revisar.']),
  createLesson('g3-mat-b1-l2', 'L2: Análise Combinatória — Princípio Fundamental', 'matematica', 'Análise combinatória conta o número de maneiras de organizar ou escolher elementos. Princípio Fundamental da Contagem (PFC): se um evento pode ocorrer de m maneiras e, independentemente, outro pode ocorrer de n maneiras, juntos ocorrem de m×n maneiras. Exemplos: senhas, placas de veículos, cardápios, itinerários. Fatorial: n! = n × (n-1) × (n-2) × ... × 1; por convenção, 0! = 1. Arranjos simples (ordem importa, sem repetição): A(n,p) = n!/(n-p)!. Permutação simples (todos os elementos, ordem importa): P(n) = n!. Combinação simples (ordem não importa): C(n,p) = n!/[p!(n-p)!] = C(n, n-p). Distinção crucial: quando usar cada fórmula? Questões ENEM: geralmente pedem raciocínio, não decoreba de fórmulas.', ['Qual a diferença fundamental entre um arranjo e uma combinação? Dê um exemplo de situação real para cada um.', 'Uma senha de 4 dígitos distintos é criada usando os algarismos 1-9. Quantas senhas diferentes são possíveis? E se os dígitos puderem repetir?']),
  createLesson('g3-mat-b1-l3', 'L3: Análise Combinatória — Permutações Especiais', 'matematica', 'Casos especiais de contagem. Permutação com repetição: n elementos com k₁ repetições do 1º tipo, k₂ do 2º...: P = n!/(k₁! × k₂! × ...). Exemplo clássico: quantos anagramas tem "BANANA"? P = 6!/(3!2!) = 60. Arranjos com repetição: quando o elemento pode ser escolhido mais de uma vez: AR(n,p) = nᵖ. Combinação com repetição (estrelas e barras): C(n+p-1, p). Permutações circulares: em arranjos circulares, um elemento é fixo e os demais se reorganizam: P_circular = (n-1)!. Exemplo: 6 pessoas ao redor de uma mesa: (6-1)! = 120 maneiras. Princípio da complementar na contagem: contar o total e subtrair os casos indesejados — mais eficiente que contar direto em muitas situações.', ['Quantos anagramas tem a palavra "MATEMATICA"? Mostre o raciocínio passo a passo.', 'De quantas maneiras 5 pessoas podem sentar ao redor de uma mesa redonda? E se 2 pessoas específicas não quiserem sentar lado a lado?']),
  createLesson('g3-mat-b1-l4', 'L4: Probabilidade — Fundamentos e Espaço Amostral', 'matematica', 'Probabilidade mede a chance de ocorrência de eventos. Conceitos fundamentais: experimento aleatório (resultado imprevisível); espaço amostral Ω (todos os resultados possíveis); evento A ⊆ Ω. Probabilidade clássica (Laplace): P(A) = n(A)/n(Ω) — quando todos os resultados são igualmente prováveis. Propriedades: 0 ≤ P(A) ≤ 1; P(Ω) = 1; P(∅) = 0. Evento complementar: P(Ā) = 1 - P(A). União de eventos: P(A ∪ B) = P(A) + P(B) - P(A ∩ B). Eventos mutuamente exclusivos (não podem ocorrer juntos): P(A ∪ B) = P(A) + P(B). Diagrama de Venn em probabilidade: visualizar interseções. Aplicações reais: seguros, epidemiologia, previsão do tempo, jogos de azar, genética.', ['Numa caixa com 5 bolas vermelhas e 3 azuis, qual a probabilidade de retirar 2 vermelhas em sequência sem reposição? E com reposição?', 'Uma carta é retirada aleatoriamente de um baralho (52 cartas). Qual a probabilidade de ser um rei OU um coração?']),
  createLesson('g3-mat-b1-l5', 'L5: Probabilidade — Condicional e Independência', 'matematica', 'Probabilidade condicional: P(A|B) = P(A ∩ B)/P(B) — probabilidade de A dado que B já ocorreu. Teorema de Bayes: P(A|B) = P(B|A)×P(A)/P(B) — fundamental em diagnósticos médicos, spam filters, IA. Eventos independentes: A e B são independentes se P(A ∩ B) = P(A)×P(B), equivalentemente P(A|B) = P(A). Sequências de eventos independentes: jogar um dado 3 vezes — cada jogada independente. Paradoxos de probabilidade: o problema de Monty Hall (Monty Hall Problem) — contra-intuitivo mas matematicamente correto. Aplicações em genética: probabilidade de herdar uma característica (leis de Mendel). Simulações: como a teoria se confirma em experimentos reais com muitas repetições (Lei dos Grandes Números).', ['O que é probabilidade condicional e por que ela é diferente da probabilidade simples? Dê um exemplo do cotidiano.', 'Explique o Problema de Monty Hall: por que mudar a escolha original dobra a probabilidade de ganhar? Use raciocínio probabilístico para justificar.']),
  createLesson('g3-mat-b1-l6', 'L6: Probabilidade — Distribuições e Binomial', 'matematica', 'Distribuições de probabilidade descrevem o comportamento de variáveis aleatórias. Variável aleatória discreta: assume valores contáveis; distribuição de probabilidade lista cada valor e sua probabilidade. Esperança matemática (valor esperado): E(X) = Σ x×P(X=x). Variância: Var(X) = E(X²) - [E(X)]². Distribuição binomial: experimentos repetidos independentes com apenas 2 resultados (sucesso/fracasso); P(X=k) = C(n,k) × pᵏ × (1-p)ⁿ⁻ᵏ. Exemplo: em 10 lançamentos de moeda, qual a probabilidade de exatamente 6 caras? Distribuição de Poisson: eventos raros em intervalo de tempo ou espaço. A distribuição normal (Gaussiana): a mais importante da estatística — sino simétrico, média = mediana = moda. Aproximação normal à binomial para n grande.', ['Calcule a esperança matemática de um dado honesto de 6 faces. Qual seria a esperança de um dado viciado com probabilidade dupla para o 6?', 'Um remédio tem 70% de eficácia. Em 8 pacientes, qual a probabilidade de exatamente 6 serem curados? Use a distribuição binomial.']),
  createLesson('g3-mat-b1-l7', 'L7: Estatística — Revisão e Aprofundamento', 'matematica', 'Revisão e aprofundamento em estatística para o ENEM. Medidas de posição: média aritmética (soma/n), média ponderada (Σ peso×valor/Σpeso), mediana (valor central após ordenação), moda (mais frequente). Medidas de dispersão: amplitude (máx - mín), variância σ² = Σ(xᵢ-x̄)²/n, desvio padrão σ = √variância, coeficiente de variação CV = σ/x̄ × 100% (permite comparar dispersões de distribuições com médias diferentes). Quartis e box plot: Q1 (25%), Q2 = mediana (50%), Q3 (75%); IQR = Q3-Q1; outliers: valores abaixo de Q1-1,5×IQR ou acima de Q3+1,5×IQR. O ENEM cobra muito a leitura crítica de gráficos e tabelas: histograma, ogiva, polígono de frequência, gráfico de setores, gráfico de barras. Cuidado com gráficos enganosos (escala manipulada).', ['Uma turma tem as notas: 4, 5, 5, 6, 7, 7, 8, 8, 9, 10. Calcule média, mediana, moda, variância e desvio padrão.', 'Como identificar um gráfico estatístico enganoso? Cite 3 técnicas manipulativas que a mídia usa e explique como cada uma distorce a realidade.']),
  createLesson('g3-mat-b1-l8', 'L8: Geometria Plana — Revisão e Aplicações ENEM', 'matematica', 'Revisão estratégica de geometria plana para o ENEM. Áreas: triângulo (base×altura/2; fórmula de Heron), quadriláteros (quadrado, retângulo, paralelogramo, trapézio, losango), círculo (πr²), polígonos regulares. Teorema de Pitágoras: a² = b² + c²; aplicações em diversas situações (diagonais de retângulos, distâncias). Semelhança de triângulos: critérios AA, LAL, LLL; razão de semelhança e razão de áreas (ao quadrado da razão linear). Círculo e circunferência: comprimento (2πr), arco, setor circular (θ/360° × πr²). Inscrito e circunscrito: triângulo inscrito em circunferência — Teorema de Tales, ângulos inscritos. Questões ENEM: muito frequente — calcular área de figuras compostas, aplicar semelhança em contexto real (planta baixa de uma casa, mapa).', ['Uma planta baixa está na escala 1:50. Uma sala mede 6 cm × 4 cm na planta. Qual é a área real da sala em m²?', 'Calcule a área da região sombreada de uma figura composta por um quadrado de lado 10 cm com um círculo inscrito. Use π = 3,14.']),
  createLesson('g3-mat-b1-l9', 'L9: Geometria Espacial — Sólidos e Volumes', 'matematica', 'Geometria espacial: o estudo de sólidos tridimensionais. Prismas: base poligonal × altura; V = Ábase × h; área lateral = perímetro da base × h. Pirâmides: V = (1/3) × Ábase × h; frustro (pirâmide truncada). Cilindro: V = πr²h; área lateral = 2πrh; área total = 2πrh + 2πr². Cone: V = (1/3)πr²h; geratriz g = √(r² + h²); área lateral = πrg. Esfera: V = (4/3)πr³; área = 4πr². Relação de Euler para poliedros convexos: V - A + F = 2 (vértices - arestas + faces). Sólidos de Platão: tetraedro (4 faces), cubo/hexaedro (6), octaedro (8), dodecaedro (12), icosaedro (20). Questões ENEM: embalagens, piscinas, reservatórios, planilhas de sólidos — sempre contextualizados.', ['Uma piscina cilíndrica tem raio de 3 m e profundidade de 1,5 m. Quantos litros de água ela comporta? (1 m³ = 1000 L)', 'Uma caixa d\'água esférica tem raio de 1,2 m. Outra tem raio de 0,6 m. A caixa maior tem quantas vezes o volume da menor?']),
  createLesson('g3-mat-b1-l10', 'L10: Trigonometria — Revisão e Funções Trigonométricas', 'matematica', 'Revisão completa de trigonometria para o ENEM. No triângulo retângulo: seno = oposto/hipotenusa, cosseno = adjacente/hipotenusa, tangente = oposto/adjacente. Valores notáveis: sen30°=1/2, cos30°=√3/2, tan30°=√3/3; sen45°=cos45°=√2/2, tan45°=1; sen60°=√3/2, cos60°=1/2, tan60°=√3. Círculo trigonométrico: ângulos em radianos (π rad = 180°); seno e cosseno de qualquer ângulo. Lei dos senos: a/senA = b/senB = c/senC (para qualquer triângulo). Lei dos cossenos: a² = b² + c² - 2bc×cosA (generaliza Pitágoras). Funções trigonométricas: y=senx, y=cosx, y=tgx — período, amplitude, domínio. Questões ENEM: altura de prédios, largura de rios, ângulos de inclinação — situações reais com triângulos.', ['Um observador no topo de um prédio de 50 m vê, sob um ângulo de depressão de 30°, a base de outro prédio. Qual é a distância horizontal entre os dois prédios?', 'Uma escada de 5 m apoia-se em uma parede formando um ângulo de 60° com o chão. A que altura da parede ela encosta? Qual a distância da base da parede ao pé da escada?']),
  createLesson('g3-mat-b1-l11', 'L11: Funções Exponenciais e Logarítmicas — Revisão', 'matematica', 'Revisão e aprofundamento de funções exponenciais e logarítmicas. Função exponencial: f(x) = aˣ (a > 0, a ≠ 1). Crescente se a > 1, decrescente se 0 < a < 1. Número e de Euler: e ≈ 2,718; fundamental em crescimento natural. Aplicações: crescimento populacional, juros compostos, decaimento radioativo, propagação de vírus. Logaritmo: logₐb = x ↔ aˣ = b. Propriedades: log(AB) = logA + logB; log(A/B) = logA - logB; log(Aⁿ) = n×logA; log_a(b) = log(b)/log(a) (mudança de base). Equações logarítmicas e exponenciais. Questões ENEM: crescimento de dívidas (juros compostos), escalas logarítmicas (Richter, decibéis, pH), modelos de crescimento e decaimento.', ['Quanto tempo leva para um capital dobrar com juros compostos a uma taxa de 10% ao ano? Use log(2) ≈ 0,301 e log(1,1) ≈ 0,041.', 'O pH de uma solução é dado por pH = -log[H⁺]. Uma solução com pH=4 tem concentração de H⁺ 100 vezes maior que uma com pH=6. Explique matematicamente por quê.']),
  createLesson('g3-mat-b1-l12', 'L12: Sequências — PA e PG Aplicadas', 'matematica', 'Progressões Aritméticas (PA) e Geométricas (PG) são estruturas matemáticas fundamentais. PA: aₙ = a₁ + (n-1)×r; Sₙ = n(a₁ + aₙ)/2. Exemplos: sequências de pagamentos mensais fixos, escadas, empilhamento linear. PG: aₙ = a₁ × qⁿ⁻¹; Sₙ = a₁(qⁿ-1)/(q-1) para q≠1. Soma de PG infinita (|q|<1): S∞ = a₁/(1-q). Exemplos: juros compostos, dividir ao meio repetidamente, dízimas periódicas. Conexões importantes: juros simples = PA; juros compostos = PG. Dízima periódica como PG: 0,333... = 3/10 + 3/100 + ... = (3/10)/(1-1/10) = 1/3. ENEM: sequências aparecem em contextos de finanças, padrões geométricos, algoritmos.', ['Uma empresa tem 100 funcionários. A cada ano, o número de funcionários cresce 20%. Em quantos anos a empresa terá mais de 500 funcionários?', 'A dízima 0,272727... pode ser escrita como fração irredutível. Use a fórmula da soma de PG infinita para encontrá-la.']),
  createLesson('g3-mat-b1-l13', 'L13: Matemática Financeira — Juros e Amortização', 'matematica', 'Matemática financeira é o conteúdo de maior aplicação prática da vida real. Juros simples: J = C×i×t; M = C(1+it) — linear. Juros compostos: M = C(1+i)ᵗ — exponencial. Diferença prática: R$10.000 a 10% a.a. por 5 anos: simples → R$15.000; compostos → R$16.105. Taxa nominal vs. taxa efetiva: taxa de 24% a.a. com capitalização mensal ≠ 2% a.m. Valor Presente e Valor Futuro: VP = VF/(1+i)ⁿ; VF = VP(1+i)ⁿ. Desconto: bancário (D = N×i×t) vs. racional (D = N×i×t/(1+it)). Sistemas de amortização: SAC (Sistema de Amortização Constante — parcelas decrescentes); PRICE (parcelas constantes — calculada por anuidades). O ENEM cobra principalmente: comparação de propostas financeiras, calcular prestações, interpretar tabelas de financiamento.', ['Você financia R$50.000 em 36 parcelas iguais a 1,5% a.m. (PRICE). Use VP = PMT × [1-(1+i)⁻ⁿ]/i para calcular a parcela mensal aproximada.', 'Compare: pagar à vista por R$2.000 ou pagar 12 prestações de R$200 (total R$2.400). Qual a taxa de juros implícita no financiamento? Compensa financiar?']),
  createLesson('g3-mat-b1-l14', 'L14: Matrizes e Determinantes — Revisão', 'matematica', 'Matrizes organizam dados em linhas e colunas. Tipos: quadrada (m=n), linha (1×n), coluna (m×1), nula (todos zeros), identidade (1 na diagonal, 0 nos demais). Operações: adição (mesma ordem), multiplicação por escalar, multiplicação de matrizes (A_{m×n} × B_{n×p} = C_{m×p} — número de colunas de A = número de linhas de B). Determinante de 2×2: det(A) = ad-bc. Determinante de 3×3: Regra de Sarrus. Propriedades: det(AB) = det(A)×det(B); det(Aᵀ) = det(A). Inversa de matriz 2×2: A⁻¹ = (1/det(A)) × adj(A). Aplicação: resolver sistema linear 2×2 usando matrizes. Regra de Cramer. O ENEM raramente cobra matrizes em cálculos complexos, mas usa o conceito de organização tabular de dados.', ['Calcule o determinante da matriz A = [[2, 3, 1], [0, 4, 2], [1, -1, 3]] usando a Regra de Sarrus.', 'Use a Regra de Cramer para resolver o sistema: 2x + y = 5 e 3x - 2y = 4. Verifique a solução substituindo.']),
  createLesson('g3-mat-b1-l15', 'L15: Sistemas Lineares — Aplicações', 'matematica', 'Sistemas lineares aparecem em situações de equilíbrio e mistura. Método de substituição, adição (eliminação) e escalonamento de Gauss-Jordan. Classificação: sistema possível determinado (SPD — 1 solução), possível indeterminado (SPI — infinitas soluções), impossível (SI — sem solução). Classificação pelo determinante: det≠0 → SPD; det=0 → SPI ou SI. Interpretação geométrica: 2 equações com 2 variáveis → 2 retas no plano; SPD = retas paralelas, SPI = retas coincidentes, SI = retas sem interseção. Aplicações práticas: problemas de misturas (misturar soluções com concentrações diferentes), problemas de idades, problemas de trabalho em conjunto, distribuição de recursos. Questões ENEM: sempre contextualizadas — compreender o problema e montar o sistema é mais importante que resolver o sistema em si.', ['Uma mistura de 40% e 70% de álcool deve resultar em 50 litros de solução a 55% de álcool. Quantos litros de cada concentração usar?', 'Dois trens partem em direções opostas. Um vai a 80 km/h, o outro a 120 km/h. Após quanto tempo estarão a 500 km de distância um do outro?']),
  createLesson('g3-mat-b1-l16', 'L16: Geometria Analítica — Reta e Circunferência', 'matematica', 'Geometria analítica une álgebra e geometria através de coordenadas. Distância entre pontos: d = √[(x₂-x₁)² + (y₂-y₁)²]. Ponto médio: M = ((x₁+x₂)/2, (y₁+y₂)/2). Equação da reta: y = ax + b (a = inclinação, coeficiente angular); ax + by + c = 0 (forma geral). Coeficiente angular: a = (y₂-y₁)/(x₂-x₁) = tan(θ). Retas paralelas: mesma inclinação (a₁=a₂). Retas perpendiculares: a₁×a₂ = -1. Distância de ponto à reta: d = |ax₀+by₀+c|/√(a²+b²). Circunferência: (x-a)²+(y-b)²=r² (centro (a,b), raio r); ou x²+y²+Dx+Ey+F=0. Posição relativa reta-circunferência: d<r (secante), d=r (tangente), d>r (externa).', ['Determine a equação da reta que passa pelos pontos A(2,-1) e B(-3,4). Qual a distância do ponto C(0,3) a essa reta?', 'Encontre o centro e o raio da circunferência x²+y²-6x+4y-3=0. Em seguida, verifique se o ponto (0,3) está dentro, sobre ou fora da circunferência.']),
  createLesson('g3-mat-b1-l17', 'L17: Simulado ENEM — 1º Bimestre (Matemática)', 'matematica', 'Simulado de Matemática estilo ENEM com 15 questões cobrindo os conteúdos do 1º bimestre: análise combinatória, probabilidade, estatística, geometria plana, geometria espacial, trigonometria, funções exponenciais/logarítmicas, sequências, matemática financeira, matrizes, sistemas lineares, geometria analítica. Protocolo de prova: 2 horas e 30 minutos; consulta à tabela trigonométrica. Correção comentada: cada questão tem a solução detalhada. Análise de erros: categorizar erros (erro de cálculo, erro de interpretação, conteúdo desconhecido). Estratégia para o ENEM real: começar pelas questões mais fáceis, não gastar mais de 5 min em uma questão, usar rascunho para esboços.', ['Analise seu desempenho no simulado: em quais conteúdos você errou mais? Qual a diferença entre errar por desatenção e errar por não saber o conteúdo?', 'Escolha as 3 questões que mais te desafiaram e resolva-as novamente com calma, identificando onde estava o erro.']),
  createLesson('g3-mat-b1-l18', 'L18: Revisão do 1º Bimestre — Plano de Ação', 'matematica', 'Revisão e síntese do 1º bimestre. Análise coletiva do simulado: quais conteúdos a turma teve mais dificuldade? Qual é o plano coletivo de reforço? Plano de ação individual: cada aluno lista seus 3 maiores pontos fracos e descreve como vai trabalhar cada um. Recursos adicionais: plataformas gratuitas (Khan Academy em português, Brasil Escola, Descomplica, YouTube — professor Ferretto, Equaciona com Paulo Pereira). A matemática do ENEM exige prática diária: resolver pelo menos 5 questões por dia de conteúdos variados. O "caderno de erros": anotar cada erro com a solução correta e revisitar semanalmente. Meta: na próxima prova, identificar quais erros do bimestre anterior foram superados.', ['Quais são seus 3 maiores pontos fracos em matemática identificados neste bimestre? Como você vai trabalhar cada um nas próximas semanas?', 'Estabeleça uma rotina de estudo de matemática para as próximas 8 semanas: quantas horas por dia, quais conteúdos, quais recursos usará.']),
];

export const matLessonsB2: Lesson[] = [
  createLesson('g3-mat-b2-l1', 'L1: Funções — Domínio, Imagem e Revisão Geral', 'matematica', 'Revisão completa do conceito de função para a 3ª Série. Função f: A → B; domínio (Dom), contradomínio (CD), imagem (Im). Condições de existência: raiz quadrada (radicando ≥ 0), fração (denominador ≠ 0), logaritmo (argumento > 0). Análise gráfica: leitura de domínio, imagem, zeros (raízes), crescimento/decrescimento, máximos e mínimos locais, paridade (função par: f(-x)=f(x); função ímpar: f(-x)=-f(x)). Composição de funções: (fog)(x) = f(g(x)); atenção à ordem — fog ≠ gof em geral. Função inversa: f⁻¹ existe quando f é bijetora; gráfico de f⁻¹ é reflexo de f em relação à y=x. Questões ENEM: muito frequentes — leitura de gráficos, domínio, composição, modelos matemáticos de situações reais.', ['Determine o domínio da função f(x) = √(x-2) / (x²-9). Mostre todos os passos e justifique cada restrição.', 'Dadas f(x) = 2x+1 e g(x) = x², calcule fog(3) e gof(3). Por que os resultados são diferentes?']),
  createLesson('g3-mat-b2-l2', 'L2: Função do 1º Grau — Aplicações Avançadas', 'matematica', 'Função afim (1º grau): f(x) = ax + b. Coeficientes: a (angular — taxa de variação) e b (linear — valor inicial). Zero da função: x₀ = -b/a. Crescente (a>0), decrescente (a<0), constante (a=0). Equação de reta e função: y = ax + b é a mesma expressão — "função afim" e "equação de reta" descrevem a mesma estrutura matemática. Sistemas de 1º grau como interseção de retas. Modelo linear: taxa de crescimento constante — exemplos: consumo de combustível, custo de produção fixo+variável, velocidade uniforme. Ponto de equilíbrio: onde custo = receita (breakeven) em problemas de gestão financeira. Questões ENEM avançadas: tabelas de tarifas progressivas (contas de água, luz, telefone com faixas lineares por faixa).', ['Uma empresa tem custo fixo de R$3.000/mês e custo variável de R$15 por unidade. Se o preço de venda é R$25/unidade, quantas unidades precisa vender para ter lucro?', 'A conta de água tem tarifa: até 10 m³, R$0,90/m³; de 10 a 20 m³, R$1,50/m³; acima de 20 m³, R$2,20/m³. Monte uma função por partes e calcule o valor para um consumo de 25 m³.']),
  createLesson('g3-mat-b2-l3', 'L3: Função do 2º Grau — Vértice, Discriminante e Aplicações', 'matematica', 'Função quadrática: f(x) = ax² + bx + c (a≠0). Forma fatorada (quando existem raízes): f(x) = a(x-x₁)(x-x₂). Forma canônica (vértice): f(x) = a(x-xᵥ)² + yᵥ. Vértice: xᵥ = -b/2a; yᵥ = -Δ/4a. Discriminante: Δ = b²-4ac; Δ>0 → 2 raízes reais distintas; Δ=0 → raiz dupla; Δ<0 → sem raízes reais. Parábola: abre para cima (a>0), para baixo (a<0). Raízes pela Fórmula de Bhaskara: x = (-b ± √Δ)/2a. Máximos e mínimos: se a>0, mínimo em xᵥ; se a<0, máximo em xᵥ. Aplicações reais: otimização (maximizar área com perímetro fixo, maximizar lucro), trajetória de projéteis, queda livre, geometria.', ['Uma bola é lançada verticalmente com velocidade inicial de 20 m/s da altura de 1,5 m. A altura é h(t) = 1,5 + 20t - 5t². Qual a altura máxima atingida? Em que tempo retorna ao solo?', 'Uma empresa vende x unidades por semana. O lucro é L(x) = -2x² + 200x - 1500. Qual a produção que maximiza o lucro e qual é o lucro máximo?']),
  createLesson('g3-mat-b2-l4', 'L4: Geometria Analítica — Cônicas', 'matematica', 'As cônicas são curvas formadas pela interseção de um cone com um plano. Elipse: (x/a)² + (y/b)² = 1 (a>b>0); focos F₁ e F₂; semi-eixo maior a, semi-eixo menor b; c² = a² - b²; PF₁ + PF₂ = 2a (constante). Hipérbole: (x/a)² - (y/b)² = 1; |PF₁ - PF₂| = 2a (constante); assíntotas y = ±(b/a)x. Parábola: y² = 4px (eixo horizontal, foco (p,0)) ou x² = 4py (eixo vertical, foco (0,p)); equidistância foco-diretriz. Aplicações fascinantes: elipse — órbitas planetárias (Kepler), refletores elípticos; parábola — antenas parabólicas, faróis, trajetórias; hipérbole — localização GPS (diferença de distâncias constante), algumas curvas hiperbólicas em física. Questões ENEM: raramente cônicas formais, mas parábola como função quadrática aparece sempre.', ['A Terra orbita o Sol em uma elipse com semi-eixo maior a = 152 milhões de km e semi-eixo menor b = 147 milhões de km. Qual é a distância entre os focos (onde está o Sol)?', 'Uma antena parabólica tem a equação x² = 8y. Onde deve ser posicionado o receptor (no foco) para captação ideal do sinal?']),
  createLesson('g3-mat-b2-l5', 'L5: Números Complexos', 'matematica', 'Números complexos estendem os reais para incluir raízes de negativos. Unidade imaginária: i = √(-1); i² = -1; i³ = -i; i⁴ = 1 (ciclo). Forma algébrica: z = a + bi (parte real a, parte imaginária b). Operações: soma [(a+bi)+(c+di) = (a+c)+(b+d)i], produto [(a+bi)(c+di) = (ac-bd)+(ad+bc)i], divisão (multiplicar pelo conjugado). Módulo: |z| = √(a²+b²). Conjugado: z̄ = a - bi. Plano de Argand-Gauss: representação geométrica no plano complexo (eixo real, eixo imaginário). Forma polar/trigonométrica: z = r(cosθ + i senθ); r = |z|; θ = arg(z). Teorema de Moivre: zⁿ = rⁿ(cos(nθ) + i sen(nθ)). Aplicações: circuitos elétricos de corrente alternada (engenharia elétrica), processamento de sinais, mecânica quântica.', ['Dados z₁ = 3 + 4i e z₂ = 1 - 2i, calcule: z₁+z₂, z₁×z₂, z₁/z₂ e |z₁|. Represente z₁ no plano de Argand.', 'Resolva no conjunto dos complexos: x² + 4x + 13 = 0. Por que essa equação não tem raízes reais mas tem raízes complexas?']),
  createLesson('g3-mat-b2-l6', 'L6: Polinômios e Equações Algébricas', 'matematica', 'Polinômios: expressão da forma p(x) = aₙxⁿ + ... + a₁x + a₀. Grau, coeficientes, raízes (zeros). Teorema do Resto: ao dividir p(x) por (x-a), o resto é p(a). Teorema do Fator: (x-a) é fator de p(x) ↔ a é raiz de p(x). Dispositivo de Briot-Ruffini: divisão rápida de polinômio por (x-a). Relações de Girard (Vieta): para x² + bx + c = 0; soma das raízes = -b, produto = c. Para polinômio de grau n: xⁿ + pxⁿ⁻¹ + ... → soma das raízes = -p, soma dos produtos 2 a 2 = seguinte coeficiente, etc. Equações algébricas de grau alto: redução de grau ao encontrar uma raiz. Equações biquadráticas (y = x²): aₓ⁴ + bx² + c = 0 → ay² + by + c = 0. Questões ENEM: raramente equações de grau 3+, mas polinômios aparecem em contexto de análise de funções.', ['Divida p(x) = 2x³ - 3x² + x + 2 por (x-2) usando Briot-Ruffini. Verifique que x=2 é raiz do polinômio.', 'Usando as relações de Girard, encontre a soma e o produto das raízes de 3x² - 12x + 9 = 0 sem calcular as raízes. Depois calcule as raízes e verifique.']),
  createLesson('g3-mat-b2-l7', 'L7: Trigonometria Avançada — Identidades e Equações', 'matematica', 'Aprofundamento em trigonometria para o ENEM avançado. Identidades fundamentais: sen²x + cos²x = 1; 1 + tan²x = sec²x; 1 + cot²x = csc²x. Fórmulas de adição: sen(A+B) = senA cosB + cosA senB; cos(A+B) = cosA cosB - senA senB; tan(A+B) = (tanA+tanB)/(1-tanA tanB). Fórmulas de duplicação: sen(2A) = 2senA cosA; cos(2A) = cos²A - sen²A = 1 - 2sen²A = 2cos²A - 1. Fórmulas de arco médio (transformações de soma em produto). Equações trigonométricas: senx = k → x = arcsen(k) + 2kπ; cosx = k. Funções trigonométricas inversas: arcsen, arccos, arctg — domínio restrito para inversão. Questões ENEM: geometria com triângulos não-retângulos (lei dos senos/cossenos) e interpretação de gráficos de funções trigonométricas.', ['Prove a identidade: sen(2x) = 2senx cosx usando a fórmula de adição do seno.', 'Resolva a equação trigonométrica 2cos²x - cosx - 1 = 0 para 0 ≤ x < 2π. Quantas soluções existem?']),
  createLesson('g3-mat-b2-l8', 'L8: Geometria Espacial — Projeções e Seções', 'matematica', 'Aprofundamento em geometria espacial. Posições relativas de retas e planos no espaço: retas paralelas, concorrentes, reversas (nem paralelas nem concorrentes, não estão no mesmo plano). Planos: posições relativas (paralelos, concorrentes, coincidentes); diedro (ângulo entre planos). Seções planas de sólidos: cortar um sólido com um plano produz diferentes figuras — corte de pirâmide, cone, cilindro, esfera. Projeções ortogonais: sombra de um ponto, segmento ou figura num plano (fundamental para leitura de plantas arquitetônicas). Sólidos de revolução: gerar um sólido girando uma figura plana em torno de um eixo — cilindro (retângulo), cone (triângulo retângulo), esfera (semicírculo). Truque prático: identificar faces, arestas e vértices em sólidos complexos.', ['Qual é a seção obtida ao cortar uma esfera com um plano? Prove que essa seção é sempre uma circunferência (ou ponto).', 'Um cone de raio 6 cm e altura 8 cm é cortado por um plano paralelo à base a 4 cm do vértice. Qual o raio e a área da seção resultante?']),
  createLesson('g3-mat-b2-l9', 'L9: Noções de Cálculo — Limites e Derivadas', 'matematica', 'Introdução ao Cálculo Diferencial — conteúdo que aparece em alguns vestibulares (FUVEST, UNICAMP) e na base do pensamento matemático avançado. Limite: intuição — o que acontece com f(x) quando x se aproxima de a? lim_{x→2} (x²-4)/(x-2) = lim(x+2) = 4. Limite e continuidade: f contínua em a se lim_{x→a} f(x) = f(a). Derivada — definição: f\'(a) = lim_{h→0} [f(a+h)-f(a)]/h — a taxa de variação instantânea. Interpretação geométrica: inclinação da reta tangente ao gráfico. Regras de derivação: d/dx(xⁿ) = nxⁿ⁻¹; d/dx(eˣ) = eˣ; d/dx(lnx) = 1/x; d/dx(senx) = cosx; d/dx(cosx) = -senx. Regra do produto, do quociente, da cadeia. Aplicações: máximos e mínimos (f\'(x)=0), velocidade (derivada da posição), taxa de variação.', ['Use a definição de derivada (limite) para calcular f\'(x) de f(x) = x². Depois verifique com a regra da potência.', 'A posição de um objeto é dada por s(t) = t³ - 6t² + 9t (metros, t em segundos). Encontre a velocidade instantânea em t=2s e os instantes em que o objeto está parado.']),
  createLesson('g3-mat-b2-l10', 'L10: Noções de Cálculo — Integral', 'matematica', 'Introdução à Integral — a operação inversa da derivada. Antiderivada (primitiva): F(x) tal que F\'(x) = f(x). Integral indefinida: ∫f(x)dx = F(x) + C. Regras básicas: ∫xⁿdx = xⁿ⁺¹/(n+1) + C; ∫eˣdx = eˣ + C; ∫(1/x)dx = ln|x| + C; ∫cosxdx = senx + C; ∫senxdx = -cosx + C. Integral definida: ∫_a^b f(x)dx = F(b) - F(a) (Teorema Fundamental do Cálculo). Interpretação geométrica: área sob a curva y=f(x) entre x=a e x=b (com sinal — área abaixo do eixo x é negativa). Cálculo de áreas entre curvas. Aplicações: área de regiões irregulares, deslocamento (integral da velocidade), trabalho (integral da força). Este conteúdo não cai diretamente no ENEM, mas é fundamental para faculdades de exatas, engenharia, física, medicina.', ['Calcule ∫(3x² - 2x + 5)dx e depois avalie a integral definida de 0 a 2.', 'Calcule a área da região limitada pelas curvas y = x² e y = x (entre os pontos de interseção). Esboce a região antes de calcular.']),
  createLesson('g3-mat-b2-l11', 'L11: Matemática e Tecnologia — Algoritmos e Lógica', 'matematica', 'A matemática é a base da computação. Lógica matemática: proposições, tabelas-verdade, operações lógicas (∧=e, ∨=ou, ¬=não, →=se...então, ↔=se e somente se). Lei de De Morgan: ¬(A∧B) = ¬A∨¬B; ¬(A∨B) = ¬A∧¬B. Equivalência lógica: p→q ≡ ¬p∨q. Algoritmos: sequência de instruções para resolver um problema — pseudocódigo, fluxograma. Complexidade de algoritmos: O(1), O(n), O(n²), O(log n) — o que cada um significa para eficiência. Criptografia básica: substituição (César), RSA como aplicação de teoria dos números (muito grandes primos). Matemática discreta: grafos, árvores, combinatória — fundamentos da ciência da computação. Big Data e estatística: como algoritmos de machine learning usam estatística.', ['Monte a tabela-verdade de (p→q) ↔ (¬p∨q) e mostre que são logicamente equivalentes.', 'Explique como funciona a criptografia RSA em termos simples. Por que é difícil "quebrar" uma chave RSA grande?']),
  createLesson('g3-mat-b2-l12', 'L12: Grandezas e Medidas — Unidades e Conversões', 'matematica', 'O domínio de unidades e conversões é essencial para o ENEM e para a vida. Sistema Internacional (SI): metro (m), quilograma (kg), segundo (s), ampere (A), Kelvin (K), mol (mol), candela (cd). Prefixos: nano (10⁻⁹), micro (10⁻⁶), mili (10⁻³), centi (10⁻²), deci (10⁻¹), deca (10¹), hecto (10²), quilo (10³), mega (10⁶), giga (10⁹). Área: 1 ha = 10.000 m², 1 km² = 10⁶ m². Volume: 1 m³ = 1000 L, 1 cm³ = 1 mL. Velocidade: 1 m/s = 3,6 km/h. Temperatura: °C = K - 273,15; °F = (9/5)°C + 32. Análise dimensional: verificar equações por compatibilidade de unidades — potentíssima ferramenta de verificação. Notação científica: 6,022×10²³ (número de Avogadro), 3×10⁸ m/s (velocidade da luz).', ['Converta: 72 km/h para m/s; 2,5 litros para cm³; 1500 mL para L; 50°F para °C.', 'Uma fazenda tem 250 hectares. Quantos campos de futebol cabem nela? (campo padrão = 100m × 68m = 6800 m²)']),
  createLesson('g3-mat-b2-l13', 'L13: Simulado Temático — Questões ENEM Contextualizadas', 'matematica', 'Simulado com 15 questões de alto nível contextualizadas (estilo ENEM). Temas: funções (1º e 2º grau), matemática financeira, estatística, probabilidade, geometria. Foco na interpretação: o ENEM apresenta textos, gráficos, tabelas e dados reais antes de fazer a pergunta matemática. A habilidade de ler o enunciado corretamente é tão importante quanto saber calcular. Erros mais comuns no ENEM de Matemática: não ler o enunciado completo, não verificar a unidade pedida, usar a fórmula errada por não entender o contexto, errar arredondamentos. Após o simulado: análise detalhada de cada questão errada — o erro foi de cálculo, de conceito ou de interpretação?', ['Após o simulado, classifique seus erros: quantos foram de interpretação? De conceito? De cálculo? Qual categoria precisa de mais atenção?', 'Resolva novamente as 3 questões mais difíceis do simulado, explicando cada passo do raciocínio como se estivesse ensinando um colega.']),
  createLesson('g3-mat-b2-l14', 'L14: Geometria — Transformações e Isometrias', 'matematica', 'Transformações geométricas preservam ou alteram figuras. Isometrias (preservam distâncias): translação (desloca — vetor de translação); rotação (gira em torno de um ponto — ângulo e sentido); reflexão (espelha em relação a uma reta). Homotetia (preserva forma, altera tamanho): razão de homotetia k — se k>0, mesma orientação; k<0, orientação oposta; |k|>1 amplia, |k|<1 reduz. Simetria: de translação (padrões periódicos), de rotação (figuras com n-fold symmetry), de reflexão. Fractais: objetos com simetria de escala (auto-semelhança) — fractal de Mandelbrot, floco de neve de Koch. A beleza matemática das transformações: mosaicos de M.C. Escher, padrões islâmicos nas mesquitas. Aplicações: computação gráfica, cristalografia, design.', ['Uma figura é submetida a uma reflexão sobre o eixo y, depois uma translação de vetor (3, -2). Descreva o resultado se a figura original tem vértice em (1, 4).', 'O que é um fractal? Explique o conceito de auto-semelhança usando o Triângulo de Sierpiński como exemplo.']),
  createLesson('g3-mat-b2-l15', 'L15: Matemática e Ciências — Modelos e Aplicações', 'matematica', 'A matemática é a linguagem das ciências. Modelagem matemática: o processo de representar situações reais com equações. Física: Leis de Newton (F=ma), lei de Hooke (F=kx), energia cinética (Ec=mv²/2), movimento uniformemente acelerado (v=v₀+at, s=s₀+v₀t+at²/2). Química: proporções estequiométricas, pH = -log[H⁺], lei dos gases (PV=nRT). Biologia: crescimento exponencial de populações (N=N₀×eʳᵗ), genética mendeliana (probabilidade). Economia: PIB, inflação composta, índices, gráficos econômicos. Astronomia: órbitas elípticas (Kepler), velocidade de escape, distâncias em anos-luz, notação científica. O papel da matemática no ENEM interdisciplinar: questões que cruzam matemática com ciências naturais ou ciências humanas.', ['Um vírus se multiplica a taxa de 15% por hora. Começando com 1.000 vírus, quantos haverá após 24 horas? Em que momento ultrapassará 1 milhão?', 'A lei de resfriamento de Newton diz que T(t) = T_amb + (T₀ - T_amb)×e^(-kt). Uma xícara começa a 90°C num ambiente de 20°C. Com k=0,05, qual a temperatura após 15 minutos?']),
  createLesson('g3-mat-b2-l16', 'L16: Raciocínio Lógico e Problemas Olímpicos', 'matematica', 'O raciocínio lógico vai além das fórmulas — é a capacidade de pensar matematicamente. Problemas clássicos: o paradoxo do mentiroso, o problema das 3 portas (Monty Hall), o problema das pontes de Königsberg (origem da teoria dos grafos — Euler, 1736). Olimpíadas de Matemática: OBMEP (Olimpíada Brasileira de Matemática das Escolas Públicas) — prova de raciocínio, não de fórmulas; nível 1 (6º-7º), nível 2 (8º-9º), nível 3 (Ensino Médio). Técnicas de resolução de problemas: Polya (entender, planejar, executar, verificar); trabalhar de trás para frente; casos extremos; simetria; invariante; indução matemática. Matemática recreativa: paradoxos, ilusões matemáticas, sequência de Fibonacci na natureza. O prazer matemático: resolver um problema difícil não é frustração — é exploração.', ['Em que condições o problema de Königsberg (atravessar todas as 7 pontes sem repetir nenhuma) tem solução? Qual foi a contribuição de Euler?', 'Escolha um problema da OBMEP de nível 3 e resolva-o, documentando seu raciocínio passo a passo (não apenas a resposta).']),
  createLesson('g3-mat-b2-l17', 'L17: Preparação Intensiva para o ENEM — Estratégias', 'matematica', 'Estratégias específicas para o ENEM de Matemática. Estrutura: 45 questões de Matemática e suas Tecnologias; 5,5 horas para a prova toda (com Ciências da Natureza — 90 questões no dia 2). Ordem de resolução: muitos especialistas recomendam começar pela redação (dia 1) e pela matemática que você sabe (dia 2). Gestão do tempo: 3,5 min por questão em média. Questões difíceis: pule, marque e volte. Rasuras: permitidas no ENEM. Chute estratégico: se eliminar 2 alternativas, chance sobe de 20% para 33%. Conteúdos mais cobrados no ENEM (análise dos últimos 10 anos): funções (25%), geometria (20%), estatística/probabilidade (15%), matemática financeira (15%), trigonometria (10%), outros (15%). Simulado full ENEM: 45 questões em 3 horas.', ['Analise os últimos 5 ENEMs de Matemática: quais conteúdos aparecem mais? Qual é a distribuição de dificuldade entre fácil, médio e difícil?', 'Faça o simulado completo de 45 questões no tempo de prova. Analise: em qual nível de dificuldade você perdeu mais pontos?']),
  createLesson('g3-mat-b2-l18', 'L18: Revisão do 2º Bimestre — Sprint Matemático', 'matematica', 'Revisão e consolidação do 2º bimestre. Temas revisados: funções (domínio, composição, inversa), 1º e 2º grau, cônicas, números complexos, polinômios, trigonometria avançada, geometria espacial, noções de cálculo (limites, derivadas, integrais), lógica e algoritmos, transformações geométricas, modelagem matemática, raciocínio lógico. Sprint matemático: resolver 30 questões em 2 horas — mistura de todos os conteúdos do bimestre. Metacognição: ao revisar, identificar quais tipos de problemas "parecem difíceis" mas são fáceis, e vice-versa. O "efeito de falsa competência": achar que sabe porque entendeu a resolução na aula não é o mesmo que saber fazer sozinho. Crie seu banco de questões resolvidas e revise-o regularmente.', ['Complete a frase honestamente: "Ainda não domino completamente o conteúdo de ____ porque ____. Meu plano é ____ para superar isso."', 'Escolha 5 questões — uma de cada conteúdo do bimestre — e explique a solução de cada uma usando linguagem própria, como se ensinasse a um aluno mais novo.']),
];

export const matLessonsB3: Lesson[] = [
  createLesson('g3-mat-b3-l1', 'L1: Sprint Final — Revisão Estratégica para o ENEM', 'matematica', 'O 3º bimestre é o mais crítico: o ENEM de novembro está próximo. Estratégia de revisão: não tentar aprender coisas novas do zero — consolidar o que já sabe e resolver dificuldades específicas. "A matemática se aprende fazendo": cada dia sem resolver questões é um dia perdido. Plano de 8 semanas: semanas 1-2 (funções + geometria plana), semanas 3-4 (probabilidade + estatística + combinatória), semanas 5-6 (trigonometria + geometria espacial), semanas 7-8 (matemática financeira + revisão geral + simulados). Recursos: resoluções comentadas de ENEMs anteriores (disponíveis gratuitamente). Identificação de padrões: questões do ENEM têm padrões — "questão sobre porcentagem disfarçada de função", "questão de geometria espacial com embalagem", etc.', ['Quais são os 3 conteúdos que você ainda sente mais insegurança? Que ação específica você vai tomar nas próximas 2 semanas para cada um?', 'Monte um plano de estudo de matemática para as próximas 8 semanas: conteúdos, quantidade de questões diárias e datas de simulados.']),
  createLesson('g3-mat-b3-l2', 'L2: Questões ENEM — Funções (Banco de Questões)', 'matematica', 'Sessão intensiva de resolução de questões do ENEM sobre funções. Questões selecionadas dos ENEMs 2015-2024 sobre: função afim (custo, tarifa, variação linear), função quadrática (máximo, mínimo, trajetória), função exponencial (crescimento, juros, decaimento), função logarítmica (escala Richter, pH, decibéis), função modular |f(x)|. Estratégia de resolução: (1) Identifique o tipo de função; (2) Extraia os dados do enunciado; (3) Monte a equação; (4) Resolva; (5) Verifique se a resposta faz sentido no contexto. Erros comuns: usar função exponencial quando o contexto é linear (ou vice-versa); não identificar que |x| = x para x≥0 e -x para x<0. Meta: resolver 15 questões com análise de cada erro.', ['Resolva 5 questões do ENEM sobre funções. Para cada uma, descreva o tipo de função identificada e a estratégia usada.', 'Qual foi a questão mais difícil que você resolveu nesta sessão? Explique por que ela era difícil e como você a superou.']),
  createLesson('g3-mat-b3-l3', 'L3: Questões ENEM — Geometria Plana e Espacial', 'matematica', 'Sessão intensiva de geometria para o ENEM. Padrões identificados em questões reais: (1) Área de figuras compostas (subtrair a área do "buraco" da figura total); (2) Problemas de embalagem (maximizar volume, minimizar material de embalagem); (3) Proporcionalidade (escala de mapa, maquete vs. real); (4) Sólidos de revolução (visualizar o sólido gerado pela rotação); (5) Cálculo de volume de reservatórios e piscinas. Dicas visuais: sempre fazer um esboço; identificar as medidas e o que se pede; verificar a unidade (m, m², m³). Questões de dificuldade alta normalmente envolvem: sólidos inscritos em outros sólidos, seções planas, problemas de otimização geométrica. Meta: 15 questões de geometria de ENEMs reais.', ['Qual tipo de questão de geometria você acha mais difícil? Resolva 3 questões desse tipo e identifique o padrão de solução.', 'Uma caixa de papelão quadrada (sem tampa) deve ser feita de uma folha 40×40 cm cortando quadrados iguais dos cantos. Qual o tamanho do quadrado que maximiza o volume da caixa?']),
  createLesson('g3-mat-b3-l4', 'L4: Questões ENEM — Probabilidade e Estatística', 'matematica', 'Sessão intensiva de probabilidade e estatística para o ENEM. Padrões frequentes: (1) Probabilidade com tabela de frequência; (2) Probabilidade condicional em contexto de saúde (teste diagnóstico, eficácia de vacina); (3) Leitura crítica de gráfico (identificar erro ou distorção em gráfico apresentado); (4) Média ponderada (notas, índices, pesquisa); (5) Desvio padrão como medida de dispersão (turmas com mesma média mas desempenhos diferentes); (6) Análise combinatória aplicada a probabilidade. Armadilhas clássicas do ENEM: não perceber que o evento pede probabilidade de pelo menos um sucesso (usar complementar); confundir P(A∩B) e P(A|B). Meta: 15 questões de probabilidade e estatística.', ['Por que a probabilidade condicional é diferente da probabilidade simples? Crie um exemplo próprio que ilustre a diferença.', 'O ENEM frequentemente apresenta gráficos com distorções. Resolva 3 questões de leitura crítica de gráficos e identifique o elemento enganoso em cada uma.']),
  createLesson('g3-mat-b3-l5', 'L5: Questões ENEM — Trigonometria', 'matematica', 'Sessão intensiva de trigonometria para o ENEM. Padrões frequentes: (1) Altura de objeto inacessível usando tangente ou seno (ângulo de elevação/depressão); (2) Lei dos senos para triângulos não-retângulos (travessia de rio, distância entre dois pontos); (3) Lei dos cossenos para triângulo com 2 lados e ângulo incluído; (4) Funções trigonométricas em gráfico — identificar período, amplitude, fase; (5) Raios (distâncias em círculo trigonométrico). Erros comuns: confundir ângulo de elevação (de baixo para cima) com ângulo de depressão (de cima para baixo); usar sen quando deveria usar cos. Tabela trigonométrica: o ENEM geralmente fornece os valores necessários no próprio enunciado. Meta: 12 questões de trigonometria de ENEMs reais.', ['Descreva uma situação real do cotidiano do Tocantins (como medir a altura de uma cachoeira ou a largura do Rio Araguaia) onde a trigonometria seria aplicada. Monte e resolva o problema.', 'Resolva 3 questões de trigonometria do ENEM, identificando: qual lei/razão foi usada, por que essa escolha foi feita e qual seria o erro se usasse a lei/razão errada.']),
  createLesson('g3-mat-b3-l6', 'L6: Questões ENEM — Matemática Financeira', 'matematica', 'Sessão intensiva de matemática financeira para o ENEM. Padrões frequentes: (1) Comparação entre propostas financeiras (juros simples vs. compostos, à vista vs. parcelado); (2) Porcentagem e variação percentual (aumento de x% seguido de redução de x% não retorna ao original!); (3) Taxa de desconto (preço com e sem desconto); (4) Inflação e poder de compra (deflacionar valores históricos); (5) Financiamento com tabela de parcelas (identificar taxa de juros implícita); (6) Tributação (IR, ICMS, ISS em contexto). Erro clássico do ENEM: aumento de 20% e redução de 20% — resultado final é -4%, não zero. Entender esse erro é entender porcentagem composta. Meta: 12 questões de matemática financeira.', ['Por que aumentar 20% e depois reduzir 20% não retorna ao valor original? Prove matematicamente e dê um exemplo numérico.', 'Analise um financiamento de carro: preço à vista R$50.000 vs. R$2.500 por mês por 24 meses. Qual a taxa de juros mensal implícita? Compensa financiar?']),
  createLesson('g3-mat-b3-l7', 'L7: Simulado 1 — Gabarito Comentado', 'matematica', 'Primeiro simulado completo do 3º bimestre: 45 questões estilo ENEM em 3 horas e 30 minutos. Após a prova: análise detalhada do gabarito comentado. Cada questão é corrigida com: (1) Conteúdo abordado; (2) Nível de dificuldade (fácil/médio/difícil); (3) Solução completa e comentada; (4) Alternativas incorretas e por que são erradas (armadilhas). Estatística pessoal: porcentagem de acertos por conteúdo, por nível de dificuldade, por tempo gasto. Objetivos: identificar quais erros foram de desatenção (deu para resolver mas errou no cálculo) vs. falta de conhecimento (não sabia o conteúdo). Plano de ação pós-simulado: foco nas próximas 2 semanas.', ['Após o simulado, sua maior dificuldade foi em qual tipo de questão: fácil (deveria ter acertado), médio (acertou/errou por pouco) ou difícil (estava fora do alcance)?', 'Para as questões que você errou por desatenção, qual estratégia você vai adotar na próxima prova para evitar esse tipo de erro?']),
  createLesson('g3-mat-b3-l8', 'L8: Questões ENEM — Análise Combinatória e Sequências', 'matematica', 'Sessão intensiva de combinatória e sequências para o ENEM. Combinatória — padrões frequentes: (1) Contagem com condições restritivas (contar arranjamentos onde X e Y não ficam juntos → total - juntos); (2) Formação de comitês/times (combinação); (3) Senhas e placas (arranjo com ou sem repetição); (4) Caminhos em grade (combinatória de caminhos mínimos). Sequências — padrões frequentes: (1) Identificar PA ou PG a partir de dados; (2) Cálculo de termo geral; (3) Soma de termos da sequência; (4) Problema de juros composto disfarçado de PG. Dica: nem toda sequência é PA ou PG — olhe para as diferenças (PA) e os quocientes (PG) antes de assumir o tipo. Meta: 12 questões de combinatória + 8 de sequências.', ['Quantos diagonais tem um polígono convexo de n lados? (dica: C(n,2) - n). Calcule para n=8 (octógono). Por que a fórmula é C(n,2) - n?', 'Uma PG tem 1º termo 2 e razão 3. O 8º termo é menor que o produto do 3º pelo 4º? Calcule ambos e compare.']),
  createLesson('g3-mat-b3-l9', 'L9: Revisão de Aritmética — Percentual e Proporcionalidade', 'matematica', 'Aritmética básica é fundamento que não pode ter lacunas no ENEM. Frações: operações, simplificação, comparação. Razão e proporção: grandezas diretamente e inversamente proporcionais; regra de três simples e composta. Porcentagem: calcular x% de N; calcular N dado que x% de N = M; variação percentual = (novo-antigo)/antigo × 100%. Porcentagem sucessiva: aumento de a% e depois b% → fator total = (1+a/100)(1+b/100). Regra de três composta: múltiplas grandezas envolvidas. Problemas de mistura: quanto de cada ingrediente para atingir concentração alvo. Divisão proporcional: dividir R$1500 em partes proporcionais a 2:3:5. Questões ENEM: quase sempre têm porcentagem embutida em contexto (índice de inflação, eficácia de vacina, taxa de desemprego).', ['O preço de um produto aumentou 15% e depois sofreu um desconto de 10%. O preço final é maior, menor ou igual ao original? Calcule a variação total.', 'Numa pesquisa, 40% dos entrevistados são mulheres. Desses, 60% votam no candidato X. No total, 45% votam no candidato X. Qual a porcentagem de homens que votam no candidato X?']),
  createLesson('g3-mat-b3-l10', 'L10: Simulado 2 — Foco em Questões Difíceis', 'matematica', 'Segundo simulado do 3º bimestre com foco em questões de nível médio-alto (questões 41-45 do ENEM). Essas questões cobram: combinação de conteúdos (ex: trigonometria + funções + geometria na mesma questão), raciocínio mais abstrato, maior número de etapas de solução. Estratégia para questões difíceis: (1) Se não souber a solução direta, tente com valores específicos; (2) Elimine alternativas impossíveis; (3) Verifique a coerência dimensional (unidades); (4) Desenhe um esboço mesmo em problemas algébricos; (5) Trabalhe de trás para frente (substitua as alternativas no enunciado). O ENEM tem 5 questões difíceis — elas equivalem a 11% da nota. Vale muito a pena treinar especificamente para elas.', ['Qual das questões difíceis do simulado você resolveu com mais criatividade? Descreva a estratégia alternativa que usou.', 'Para uma das questões difíceis que errou, tente as 5 estratégias alternativas descritas. Alguma delas levou à resposta certa?']),
  createLesson('g3-mat-b3-l11', 'L11: Geoplano e Geometria Visual', 'matematica', 'Geometria visual reforça a intuição geométrica fundamental para o ENEM. Geoplano: malha de pontos onde se constroem figuras com borracha; permite explorar área (fórmula de Pick: A = I + B/2 - 1, onde I=pontos internos, B=pontos na borda), perímetro e ângulos. Teorema de Pick: para polígono com vértices em pontos inteiros; A = I + B/2 - 1. Papel quadriculado como geoplano digital: desenhar, contar e calcular. Redes (planificações) de sólidos: desdobrar um cubo ou cilindro para calcular a área total. Dobramento origami e geometria: como dobrar papel gera formas geométricas precisas. Tangram: figuras compostas das 7 peças — explorar áreas e transformações. Visualização espacial: praticar rotação e reflexão mental de figuras 3D — habilidade fundamental para engenharia e arquitetura.', ['Use o Teorema de Pick para calcular a área de um polígono com vértices em (0,0), (4,0), (4,3), (2,5), (0,3) em papel quadriculado.', 'Planifique um cubo: quantas planificações distintas existem para um cubo? Desenhe pelo menos 3 diferentes e explique por que são distintas.']),
  createLesson('g3-mat-b3-l12', 'L12: Revisão Final — Todos os Conteúdos', 'matematica', 'Revisão geral de todos os conteúdos do ano e do Ensino Médio. Mapa mental da matemática do Ensino Médio: (1) Álgebra — equações, funções, polinômios, matrizes, sistemas; (2) Geometria plana — áreas, semelhança, trigonometria; (3) Geometria espacial — volumes, áreas de superfície; (4) Geometria analítica — reta, circunferência, cônicas; (5) Combinatória e probabilidade — análise combinatória, distribuições; (6) Estatística — medidas de posição e dispersão; (7) Matemática financeira — juros, amortização; (8) Noções de cálculo (para vestibulares específicos). Identificar os "blocos" de conteúdo que o ENEM mais cobra e priorizar. Última semana antes do ENEM: revisar erros do caderno de erros, não estudar coisas novas, dormir bem.', ['Construa um mapa mental de toda a matemática do Ensino Médio. Quais conexões entre diferentes áreas você identificou?', 'Liste os 10 conceitos matemáticos que você considera mais importantes para o ENEM e explique brevemente cada um.']),
  createLesson('g3-mat-b3-l13', 'L13: Matemática Aplicada — Engenharia, Medicina e Ciências', 'matematica', 'A matemática é ferramenta universal. Engenharia: cálculo estrutural (equações diferenciais), otimização (minimizar custo, maximizar resistência), estatística de controle de qualidade. Medicina: modelos epidemiológicos (SIR — Susceptible, Infected, Recovered), probabilidade em diagnóstico (sensibilidade, especificidade, valor preditivo), farmacocinética (decaimento exponencial de drogas no organismo). Biologia: genética de populações (teorema de Hardy-Weinberg), modelagem de ecossistemas. Economia: modelos macroeconômicos, teoria dos jogos (Nash). Ciência de dados/IA: álgebra linear, estatística bayesiana, otimização por gradiente. No Tocantins: matemática aplicada ao agronegócio (cálculo de área de safras, modelagem de crescimento de rebanho, irrigação).', ['Escolha uma área profissional que te interessa e explique como a matemática é usada nela. Seja específico — quais conceitos matemáticos exatamente?', 'Como o modelo epidemiológico SIR usa equações diferenciais para prever a progressão de uma epidemia? O que cada parâmetro do modelo representa?']),
  createLesson('g3-mat-b3-l14', 'L14: Mentoria de Matemática — Ensinar para Aprender', 'matematica', 'Ensinar matemática é uma das formas mais eficazes de aprender. Projeto de mentoria: alunos com maior domínio de um conteúdo específico ensinam aqueles com mais dificuldade nesse conteúdo. A Técnica Feynman: (1) Escolha um conceito; (2) Explique-o como se fosse ensinar a uma criança de 10 anos; (3) Identifique onde sua explicação trava ou fica confusa — essas são suas lacunas; (4) Revise e simplifique. Duplas de mentoria: cada aluno identifica um conteúdo que domina bem e um que tem dificuldade. Troca de posições: o que ensina também aprende ao responder perguntas. Benefício mútuo: quem ensina consolida o conhecimento; quem recebe a mentoria tem uma perspectiva diferente da do professor.', ['Qual conteúdo matemático você domina bem o suficiente para ensinar a um colega? Escreva uma mini-aula de 10 minutos sobre ele.', 'Após ensinar um colega, o que você percebeu que não dominava tão bem quanto pensava? O que precisou revisar para explicar melhor?']),
  createLesson('g3-mat-b3-l15', 'L15: Gestão de Tempo e Estratégia no Dia do ENEM', 'matematica', 'A prova de Matemática no ENEM tem 45 questões em conjunto com 45 de Ciências da Natureza (total 90 questões no Dia 2, com a redação no Dia 1). Tempo total: 5 horas e 30 minutos. Estratégia de tempo para matemática: ~3 minutos por questão → 135 minutos para 45 questões. Reservar 30-45 min para as questões mais difíceis ao final. Estratégia de ordem: leia rapidamente todas as questões e marque por dificuldade (fácil ✓, médio ○, difícil ×). Resolva todas as fáceis, depois as médias, por último as difíceis. Questão travada: se passou de 4 minutos sem progressão, marque e continue. Chute inteligente: ao final, nunca deixar em branco — 20% de chance é melhor que 0%. Materiais necessários: caneta preta, documento oficial, lanche, água. Cuidados especiais: celular desligado e fora da sala, chegar 30 min antes, não revisar na fila.', ['Descreva sua estratégia pessoal para a prova de matemática do ENEM: ordem de resolução, gestão de tempo, critério para pular questões.', 'Faça uma simulação cronometrada de 135 minutos com 45 questões para treinar a gestão de tempo. Como foi? O que ajustaria?']),
  createLesson('g3-mat-b3-l16', 'L16: Saúde Mental na Reta Final', 'matematica', 'A reta final do ENEM é tensa. Estratégias para manter a saúde mental: (1) O estudo de qualidade supera o de quantidade — 3 horas focadas > 8 horas dispersas; (2) Técnica Pomodoro: 25 minutos de foco total + 5 min de pausa; (3) Exercício físico diário (30 min) melhora a cognição e o humor; (4) Sono: 8 horas consolida a memória estudada — não cortar o sono para estudar mais nas últimas semanas; (5) A ansiedade é normal — técnicas de respiração (4-7-8), grounding (5 sentidos); (6) A matemática não é seu inimigo — é uma ferramenta que você aprendeu a usar. Mensagem importante: você já fez mais do que imagina. O treinamento aconteceu. Confie no processo. Seu melhor é suficiente.', ['Como você está gerenciando a ansiedade na reta final do ENEM? Quais técnicas você está usando e quais funcionam melhor para você?', 'Escreva uma carta de encorajamento para si mesmo, para abrir no dia antes do ENEM. O que você precisaria ouvir nesse momento?']),
  createLesson('g3-mat-b3-l17', 'L17: Simulado Final — Condições Reais', 'matematica', 'Simulado final do 3º bimestre em condições idênticas ao ENEM real. 45 questões em 3h30min. Mesa limpa, sem consulta, sem celular. Após a prova: correção com gabarito comentado. Análise longitudinal: comparar com o simulado do 1º bimestre — quantas questões a mais acertou? Qual é a tendência? Projeção de nota: cada acerto equivale a ~2,2 pontos (ENEM usa TRI — Teoria de Resposta ao Item, não é linear, mas serve como estimativa). Meta mínima de 600 pontos de Matemática para a maioria dos cursos em universidades federais. Meta de 700+ para cursos mais concorridos. Celebração dos progressos: o crescimento ao longo do ano é o indicador mais importante.', ['Compare seus resultados no simulado final com o simulado do início do ano. Quantos pontos a mais você estima ter? O que mais contribuiu para esse progresso?', 'Se sua nota ainda está abaixo da meta, quais são as estratégias específicas para as últimas semanas? Se já atingiu a meta, como mantê-la?']),
  createLesson('g3-mat-b3-l18', 'L18: Revisão do 3º Bimestre — Plano Final', 'matematica', 'Revisão do 3º bimestre e elaboração do plano final para o ENEM. Conteúdos do 3º bimestre: sprint de revisão (funções, geometria, probabilidade, trigonometria, financeira, combinatória), 2 simulados completos, cálculo e álgebra avançados, raciocínio lógico, geometria visual, revisão final. Plano final para o ENEM: cada aluno elabora um cronograma para as últimas semanas, definindo: conteúdos a revisar, simulados a fazer, dias de descanso, gestão da véspera. A matemática é processo, não resultado: o ENEM mede uma parte do que você sabe — não mede criatividade, esforço, caráter nem potencial. Qualquer que seja o resultado, a jornada de 3 anos de estudo matemático formou habilidades que durarão para sempre.', ['Escreva seu plano final para as semanas até o ENEM: conteúdos, simulados, descanso. Seja realista e específico.', 'O que a matemática te ensinou além dos cálculos? Quais habilidades de raciocínio, resolução de problemas e perseverança você desenvolveu?']),
];

export const matLessonsB4: Lesson[] = [
  createLesson('g3-mat-b4-l1', 'L1: Pós-ENEM — Reflexão e Novos Horizontes', 'matematica', 'O ENEM passou. Momento de reflexão matemática: como foi a prova? Quais questões surpreenderam? Quais você sabia mas não conseguiu resolver sob pressão? Análise coletiva do gabarito: resolução comentada das questões mais difíceis do ENEM 2026. Correção da nota esperada (TRI). A matemática além do ENEM: o que vem a seguir — álgebra linear, cálculo diferencial e integral, estatística avançada, probabilidade formal. Como a faculdade usa o que foi aprendido: cada área usa a matemática de forma diferente. Mensagem: a matemática não termina aqui — ela se aprofunda e se transforma na vida universitária e profissional.', ['Como foi sua experiência na prova de matemática do ENEM? Quais questões você achou mais desafiadoras e por quê?', 'Reflita: o que você aprendeu de matemática ao longo dos 3 anos que vai usar na sua vida independentemente do resultado no ENEM?']),
  createLesson('g3-mat-b4-l2', 'L2: Matemática para Diferentes Carreiras', 'matematica', 'Cada carreira usa a matemática de forma diferente. Engenharia: cálculo vetorial, equações diferenciais, álgebra linear, transformadas de Fourier. Medicina/Biológicas: estatística biomedical, cálculo de dosagem, probabilidade em diagnóstico, modelos epidemiológicos. Economia/Administração: matemática financeira avançada, estatística econométrica, pesquisa operacional, teoria dos jogos. Ciências da Computação: álgebra booleana, teoria dos grafos, complexidade computacional, criptografia. Ciências Humanas/Sociais: estatística social, análise de dados, leitura crítica de gráficos e pesquisas. Artes/Design: geometria, proporção áurea, fractais, simetria. Direito: lógica formal, estatística processual. Não existe carreira que não use matemática — a questão é qual nível e qual tipo.', ['Para a carreira que você pretende seguir, quais áreas da matemática serão mais relevantes? Pesquise e descreva.', 'Por que mesmo profissões não técnicas (jornalismo, marketing, direito) exigem um mínimo de letramento matemático e estatístico?']),
  createLesson('g3-mat-b4-l3', 'L3: Matemática Universitária — Prévia', 'matematica', 'Uma prévia do que você encontrará na matemática universitária. Cálculo I: limites, derivadas, integrais — a base de toda engenharia e ciências naturais. Álgebra Linear: vetores, matrizes, espaços vetoriais — fundamento de machine learning e computação gráfica. Probabilidade e Estatística: modelagem estatística, inferência, teste de hipóteses — essencial em pesquisa e ciência de dados. Matemática Discreta: grafos, combinatória, lógica — computação. Como a matemática do Ensino Médio se conecta: funções → cálculo; matrizes → álgebra linear; probabilidade → estatística. Dificuldades esperadas: a transição para o nível universitário é real — o ritmo é mais rápido, a abstração é maior. Estratégias para não se perder no 1º semestre de exatas.', ['Qual área da matemática universitária você está mais curioso para explorar? Por quê?', 'Pesquise o currículo do 1º semestre do curso que você quer fazer. Quais disciplinas de matemática terá? Como o que aprendeu no Ensino Médio se conecta?']),
  createLesson('g3-mat-b4-l4', 'L4: História da Matemática — Uma Jornada Civilizacional', 'matematica', 'A matemática é uma das maiores conquistas da humanidade. Origem: Mesopotâmia (~3000 a.C.) — aritmética para comércio e astronomia; Egito — geometria para o Nilo; Grécia — prova matemática (Euclides, "Elementos", ~300 a.C.). O zero: inventado na Índia (~500 d.C.) por Brahmagupta; revolucionou a aritmética. Álgebra: Al-Khwarizmi (Iraque, ~800 d.C.) — o nome "álgebra" vem do árabe "al-jabr". Renascimento matemático: Fibonacci, Tartaglia, Cardano. Iluminismo: Newton e Leibniz — cálculo diferencial e integral (simultâneo, independente, polêmica de prioridade). Séc. XIX-XX: Galois (teoria dos grupos), Riemann (geometria não-euclidiana), Cantor (infinito), Gödel (incompletude), Turing (computação). A matemática como arte: Hardy ("Apologia de um Matemático") — matemática como exploração pura.', ['Por que a invenção do zero foi tão revolucionária para o desenvolvimento da matemática? O que não era possível antes dessa invenção?', 'O que é o Teorema da Incompletude de Gödel e por que ele foi uma revolução filosófica não apenas matemática?']),
  createLesson('g3-mat-b4-l5', 'L5: Paradoxos e Beleza Matemática', 'matematica', 'A matemática tem beleza, paradoxos e profundidade infinita. Paradoxos: o paradoxo de Zenão (Aquiles e a tartaruga — infinitas somas de parcelas cada vez menores podem ser finitas); o paradoxo de Bertrand Russell (conjunto de todos os conjuntos que não se contêm — destruiu os fundamentos da teoria dos conjuntos); o paradoxo do aniversário (23 pessoas numa sala: >50% de chance de 2 fazerem aniversário no mesmo dia). Números notáveis: π (irracional, transcendente — infinitos decimais sem padrão); e (base dos logaritmos naturais); φ (razão áurea = (1+√5)/2 ≈ 1,618 — em espirais na natureza, arquitetura grega, proporções). Identidade de Euler: eⁱᵖ + 1 = 0 — considerada a equação mais bela da matemática (conecta e, i, π, 1 e 0). Números primos: padrão misterioso, fundamental em criptografia.', ['Resolva o Paradoxo de Zenão matematicamente: Aquiles corre a 10 m/s, a tartaruga começa 100 m à frente a 1 m/s. Quando Aquiles alcança a tartaruga? Use a soma de PG infinita.', 'Por que a Identidade de Euler (eⁱᵖ + 1 = 0) é chamada de "a equação mais bela da matemática"? Explique o significado de cada constante envolvida.']),
  createLesson('g3-mat-b4-l6', 'L6: Matemática e Arte — Proporção, Fractais e Música', 'matematica', 'A matemática está em toda forma de arte. Proporção áurea (φ): em pinturas (Leonardo da Vinci, Mondrian), arquitetura (Partenon, Notre-Dame), natureza (espiral de girassol, concha nautilus), o rosto humano. Spirais de Fibonacci: a sequência 1,1,2,3,5,8,13,21... aparece em pinhas de pinheiro, flores de girassol, galaxias espirais. Fractais na arte: as obras de Jackson Pollock têm dimensão fractal 1,45 (estudos da Universidade de Oregon); o fractal de Mandelbrot gerou a arte computacional. Matemática na música: as frequências das notas musicais são razões matemáticas precisas (oitava = freq×2, quinta = freq×3/2); Pitágoras descreveu a harmonia musical com proporções. Bach e a simetria matemática: fugas construídas como transformações matemáticas de temas. Perspectiva na pintura: Brunelleschi inventou a perspectiva linear com geometria projativa.', ['Como a proporção áurea aparece na natureza e na arte? Por que ela é percebida como "esteticamente agradável"?', 'Calcule as frequências das notas musicais da escala dó maior (dó, ré, mi, fá, sol, lá, si, dó) sabendo que dó4 = 261,63 Hz. Qual é o padrão matemático?']),
  createLesson('g3-mat-b4-l7', 'L7: Desafios Matemáticos em Aberto', 'matematica', 'A matemática tem problemas não resolvidos que desafiam os maiores gênios. Problema de Hilbert: em 1900, Hilbert listou 23 problemas para o século XX. Problemas do Milênio (Millennium Prize Problems, US$1 milhão cada): 1) Hipótese de Riemann (sobre zeros da função zeta); 2) P vs. NP (todo problema cuja solução é verificável rapidamente também pode ser resolvido rapidamente?); 3) Equações de Navier-Stokes (fluidos); 4) Conjectura de Birch e Swinnerton-Dyer; 5) Conjectura de Hodge; 6) Equações de Yang-Mills; 7) Hipótese de Poincaré (resolvida por Perelman em 2003 — ele recusou o prêmio!). Conjectura de Goldbach: todo número par maior que 2 é soma de dois primos — parece simples, não foi provada. A matemática é infinita — sempre haverá novos territórios a explorar.', ['O que é o problema P vs. NP e por que ele é considerado o mais importante da ciência da computação e da matemática?', 'O matemático russo Grigori Perelman resolveu a Hipótese de Poincaré e recusou o prêmio de US$1 milhão. O que isso revela sobre a natureza da matemática como vocação?']),
  createLesson('g3-mat-b4-l8', 'L8: Matemática do Cotidiano — Decisões Racionais', 'matematica', 'A matemática mais útil na vida não é equações diferenciais — é o raciocínio numérico para tomar boas decisões. Educação financeira pessoal: entender juros compostos (o "milagre dos juros" — R$200/mês investido a 0,8% a.m. por 30 anos = R$300.000); diferença entre renda fixa e renda variável; o poder do tempo nos investimentos (começar aos 25 anos vs. 35 anos). Leitura crítica de notícias: o que "crescimento de 5%" significa? Crescimento de 5% sobre qual base? A falácia estatística "2x mais" — 2x mais propenso de 1% = 2%. Como não ser enganado por estatísticas: correlação ≠ causalidade (sorvete e afogamento — ambos sobem no verão); amostras tendenciosas; médias que escondem desigualdade. Votações e paradoxos: paradoxo de Condorcet em eleições.', ['Como o efeito dos juros compostos pode transformar pequenos investimentos regulares em grandes patrimônios ao longo do tempo? Faça um cálculo concreto.', 'Explique a diferença entre correlação e causalidade usando um exemplo concreto. Por que essa confusão é perigosa na interpretação de notícias?']),
  createLesson('g3-mat-b4-l9', 'L9: Projeto Final — Modelagem Matemática', 'matematica', 'Projeto final de matemática: modelagem de um problema real do Tocantins ou do Brasil. Grupos de 3-4 alunos escolhem um problema: (a) Crescimento da população de Palmas (modelo logístico); (b) Previsão de colheita de soja no TO (modelo de regressão); (c) Análise do tráfego na Av. Teotônio Segurado (teoria das filas); (d) Epidemiologia de dengue no TO (modelo SIR); (e) Impacto do desmatamento no Cerrado (modelo exponencial). Etapas: coletar dados reais, escolher o modelo matemático adequado, calibrar o modelo, fazer previsões, discutir limitações. Apresentação: 15 minutos por grupo com gráficos e análise. Objetivo: vivenciar o processo científico usando matemática como ferramenta.', ['Qual problema real do Tocantins o seu grupo escolheu para modelar? Quais dados você coletou e qual modelo matemático parece mais adequado?', 'Quais são as principais limitações do modelo matemático que você construiu? O que ele não captura da realidade?']),
  createLesson('g3-mat-b4-l10', 'L10: Apresentação do Projeto de Modelagem — Grupo 1', 'matematica', 'Apresentações dos projetos de modelagem matemática. Cada grupo de 3-4 alunos apresenta: o problema escolhido, os dados coletados, o modelo matemático usado e justificativa, os cálculos e gráficos, as previsões ou conclusões, as limitações do modelo. Critérios de avaliação: rigor matemático (fórmulas corretas, cálculos precisos), qualidade dos dados (fontes confiáveis, representativos), interpretação (o que os números significam?), apresentação (clareza, organização, resposta a perguntas). Após cada apresentação: perguntas da turma e do professor. O professor avalia tanto a matemática quanto a capacidade de comunicar resultados matemáticos para um público geral.', ['O que diferenciou a matemática que você usou no projeto da matemática que você faz em exercícios de sala? O que é diferente na modelagem real?', 'Após ver as apresentações dos colegas, quais modelos matemáticos você achou mais criativos ou mais relevantes para o Tocantins? Por quê?']),
  createLesson('g3-mat-b4-l11', 'L11: Avaliação Final e Portfólio', 'matematica', 'Avaliação final e construção do portfólio de matemática da 3ª Série. O portfólio documenta a jornada do ano e do Ensino Médio. Componentes: (1) Progresso nos simulados: comparação das notas dos simulados do ano; (2) Conteúdo favorito: qual área da matemática foi mais interessante e por quê; (3) Maior dificuldade superada: qual problema ou conteúdo parecia impossível e como foi superado; (4) Aplicação prática: um problema real onde você usou matemática fora da escola; (5) Reflexão sobre o projeto de modelagem; (6) Carta para um aluno do 1º ano sobre como estudar matemática. Avaliação: não apenas a prova final, mas a trajetória de crescimento ao longo do ano.', ['Qual foi sua maior evolução em matemática ao longo deste ano? O que você hoje consegue fazer que não conseguia no início do ano?', 'Escreva a carta para um aluno que está começando o Ensino Médio: o que você gostaria de ter sabido no 1º ano sobre como estudar matemática?']),
  createLesson('g3-mat-b4-l12', 'L12: Matemática e Cidadania — Letramento Numérico', 'matematica', 'O letramento matemático (numeracy) é uma habilidade de cidadania. Ser matematicamente letrado significa: entender gráficos de jornais, interpretar estatísticas de pesquisas, calcular juros de um financiamento, entender a diferença entre média e mediana em distribuições desiguais, reconhecer falácias estatísticas em discursos políticos. Estudos: adultos com baixo letramento matemático tomam piores decisões financeiras, de saúde e políticas. Exemplos de uso político da matemática: como a escala de um gráfico pode inflar ou minimizar uma crise; como "risco relativo" vs. "risco absoluto" muda a percepção de uma medicina; como mapas eleitorais distorcem a percepção da votação. A matemática como ferramenta de poder e de resistência — quem entende os números não é enganado por eles.', ['Cite 3 exemplos de como a matemática (estatística, probabilidade, gráficos) é usada na política ou na mídia para manipular a opinião pública.', 'Como o letramento matemático se relaciona com o exercício da cidadania? Por que um cidadão que entende números é mais difícil de enganar?']),
  createLesson('g3-mat-b4-l13', 'L13: Leitura — Grandes Matemáticos Brasileiros', 'matematica', 'O Brasil tem uma tradição matemática menos reconhecida do que merece. Léo Beisiegel (1922-1990): fundador do IMPA (Instituto Nacional de Matemática Pura e Aplicada) e um dos maiores matemáticos brasileiros do séc. XX. IMPA: é considerado um dos 10 melhores institutos de matemática do mundo; localizado no Rio de Janeiro; tem o único Prêmio Fields (a "Nobel da Matemática") de uma instituição latino-americana na história, de Artur Avila. Artur Avila: nascido no Rio de Janeiro em 1979; Prêmio Fields em 2014 (pela primeira vez para um latinoamericano); pesquisa sobre teoria dos sistemas dinâmicos. Marcelo Viana: diretor do IMPA, pesquisa caos e sistemas dinâmicos. OBMEP: projeto que identifica e forma talentos matemáticos em escolas públicas. O Brasil pode ser grande em matemática.', ['O que é o Prêmio Fields e por que a conquista de Artur Avila em 2014 foi tão significativa para a matemática latino-americana?', 'Como a OBMEP (Olimpíada Brasileira de Matemática das Escolas Públicas) contribui para o desenvolvimento da matemática no Brasil? Você já participou ou consideraria participar?']),
  createLesson('g3-mat-b4-l14', 'L14: Revisão Lúdica — Jogos e Matemática', 'matematica', 'A matemática é a base de muitos jogos. Xadrez: combinatória (o número de posições possíveis de xadrez é maior que o número de átomos no universo — 10¹²⁰ vs. 10⁸⁰); teoria dos jogos; avaliação posicional. Cubo Mágico (Rubik\'s Cube): teoria dos grupos — o conjunto de estados do cubo forma um grupo matemático com ~43 quintilhões de estados; foi resolvido em 20 movimentos ou menos (God\'s Algorithm). Poker: probabilidade, valor esperado, teoria dos jogos (Nash equilibrium). Xadrez e computação: Deep Blue vs. Kasparov (1997), AlphaZero. Go: 10¹⁷⁰ posições possíveis — mais complexo que o xadrez; AlphaGo venceu o campeão mundial em 2016. Sudoku: combinatória, busca algorítmica, satisfação de restrições. Sessão prática: torneio de jogos matemáticos.', ['Como o Cubo Mágico de Rubik se relaciona com a teoria dos grupos em matemática? O que significa dizer que os movimentos do cubo formam um "grupo"?', 'Por que o jogo de Go é considerado mais difícil para um computador vencer do que o xadrez? O que o sucesso do AlphaGo revela sobre a IA?']),
  createLesson('g3-mat-b4-l15', 'L15: Avaliação de Impacto — 3 Anos de Matemática', 'matematica', 'Avaliação de impacto do aprendizado matemático ao longo do Ensino Médio. Comparação: simulado diagnóstico do 1º dia da 1ª Série (se disponível) vs. simulado final da 3ª Série — quanto cresceu? O crescimento não é linear: há períodos de plateau seguidos de saltos. O que a matemática desenvolveu além do cálculo: raciocínio lógico (identificar premissas e conclusões), resolução de problemas (estratégias quando não se sabe a solução de imediato), perseverança (continuar quando parece impossível), precisão (a importância de ser exato), abstração (trabalhar com objetos que não existem fisicamente). Estas habilidades são transferíveis para toda a vida. Avaliação 360°: professor avalia aluno, aluno se autoavalia, alunos avaliam a disciplina.', ['Além de conteúdos matemáticos, quais habilidades de raciocínio você desenvolveu ao longo dos 3 anos? Como você as usa fora da matemática?', 'Avalie a disciplina de Matemática ao longo do Ensino Médio: o que foi bem? O que poderia ter sido diferente? O que você recomendaria para o professor do próximo ano?']),
  createLesson('g3-mat-b4-l16', 'L16: Matemática na Vida que Começa', 'matematica', 'Encerramento: como a matemática acompanha a vida adulta. Finanças pessoais: o poder dos juros compostos nos investimentos de longo prazo; o perigo das dívidas com juros compostos (cartão de crédito a 15% a.m. = 435% ao ano); como calcular se um financiamento vale a pena. Leitura de mundo: interpretar gráficos, pesquisas e estatísticas que aparecem nas notícias. Universidade e carreira: a matemática que você vai precisar. Pensamento científico: o método hipotético-dedutivo é uma forma de raciocínio matemático. A matemática está em todo lugar: em música, arquitetura, culinária (proporções), programação, medicina, esportes, arte. Você já é mais matemático do que imagina — e vai continuar se tornando mais ao longo da vida.', ['Como você pretende usar a matemática na sua vida cotidiana e profissional? Seja específico — dê pelo menos 3 exemplos concretos.', 'O que você quer dizer para a matemática como disciplina ao final deste ano? Foi uma relação de amor, ódio, ou algo mais complexo? Por quê?']),
  createLesson('g3-mat-b4-l17', 'L17: Celebração — Última Aula de Matemática', 'matematica', 'A última aula de Matemática do Ensino Médio merece celebração. Atividade final: "Matemática que me marcou" — cada aluno apresenta em 2 minutos: um problema que resolveu e se orgulhou, um conceito que o surpreendeu, uma conexão entre matemática e algo que ama (arte, esporte, música, etc.). Roda de gratidão: o professor reconhece o crescimento de cada aluno — não apenas os melhores notas, mas o maior esforço, a maior perseverança, o maior progresso. Encerramento: o professor lê um trecho de G.H. Hardy ("Apologia de um Matemático") ou Carl Sagan sobre a matemática como linguagem universal. Foto coletiva da turma. Uma última equação escrita no quadro: eⁱᵖ + 1 = 0 — a mais bela. Parabéns, matemáticos.', ['Qual foi o momento matemático que mais te marcou ao longo deste ano? Uma resolução específica, um conceito, uma aula?', 'Complete: "A matemática me ensinou que..." Compartilhe com a turma.']),
  createLesson('g3-mat-b4-l18', 'L18: Encerramento — O Infinito Começa Aqui', 'matematica', 'A última aula do ano. A matemática é infinita — não termina com o Ensino Médio, mas se transforma. Para os que vão para exatas, ciências ou tecnologia: a matemática universitária será um território novo, fascinante e desafiador. Para os que vão para outras áreas: a matemática continuará presente em formas inesperadas. Para todos: o raciocínio matemático — a capacidade de analisar, provar, questionar e resolver — é uma das ferramentas mais poderosas que um ser humano pode ter. Você passou 3 anos desenvolvendo essa ferramenta. Use-a bem. "Deus fez os inteiros; todo o resto é obra do homem" (Leopold Kronecker). Mas é uma obra magnífica. Boa sorte e bom estudo — para sempre.', ['Se você pudesse resumir o aprendizado de 3 anos de Matemática no Ensino Médio em uma única frase, qual seria?', 'Escreva uma mensagem para seus filhos ou alunos do futuro sobre por que a matemática importa. O que você gostaria que eles soubessem antes de começar essa jornada?']),
];
